if (arguments.length > 1) {
    //当前已选中的行内容（可能是多行）
    let data = arguments[1].selection;

    // 给全局变量赋值
    $Variable.selectPUInstancesList = data;

    // 统计节点状态（根据最新的数据来源）
    let undeployNodeCount = 0;
    let deployedStartedCount = 0; // 已部署且已启动
    let deployedStoppedCount = 0; // 已部署但未启动
    let unnormalNodeCount = 0;
    let partDeployCount = 0; // 部分部署

    // 处理每个选中数据
    for (let i = 0; i < data.length; i++) {
        let nodeItem = data[i];

        if ("已部署" === nodeItem.deploy_state) {
            if ("已启动" === nodeItem.running_state || "部分启动" == nodeItem.running_state) {
                deployedStartedCount++;
            } else if ("未启动" === nodeItem.running_state) {
                deployedStoppedCount++;
            }
        } else if ("未部署" === nodeItem.deploy_state) {
            undeployNodeCount++;
        } else if ("部分部署" == nodeItem.deploy_state){
            partDeployCount++;
        } else if("异常" == nodeItem.deploy_state){
            unnormalNodeCount++;
        }
    }

    // 向父页面传参
    let parentPageName = "运维部署管理_框架页面";
    let selectedNodeStatus = {
        undeployNodeCount,
        deployedStartedCount,
        deployedStoppedCount,
        unnormalNodeCount,
        partDeployCount
    };
    SetVariable(parentPageName, 'selectedNodeStatus', selectedNodeStatus);

    // 触发父页面脚本执行
    GetVariable(parentPageName, 'updatePUButtonStatus');
}

